select count(1)
  from batch.outbox_event
 where tenant_id = #{tenantId}
   and publish_status in

    #{status}

select count(1)
  from batch.outbox_event
 where tenant_id = #{tenantId}
   and publish_status = #{publishingStatus}
   and updated_at < current_timestamp - (#{timeoutSeconds} * interval '1 second')

select count(1)
  from batch.job_instance
 where tenant_id = #{tenantId}
   and instance_status in

    #{status}

select count(1)
  from batch.worker_registry
 where tenant_id = #{tenantId}
   and status = 'ONLINE'
   and (
     (#{workerGroup} is null and worker_group is null)
     or worker_group = #{workerGroup}
   )
